+export function useLiveEvents(
+  onEvent: (payload: LiveEventPayload) => void,
+): void {
+  const onEventRef = useRef(onEvent);
+  onEventRef.current = onEvent;
+
+  useEffect(() => subscribeToLiveEvents((payload) => onEventRef.current(payload)), []);
+}
